@dataclass
class PhylacteryCommit:
    content: str
    parent_hash: str
    timestamp: float = field(default_factory=time.time)
    hash: str = ""

    def __post_init__(self):
        if not self.hash:
            self.hash = hashlib.sha256(
                (self.parent_hash + self.content).encode()
            ).hexdigest()


